const { all } = msg.payload || {};
const path = `/containers/json${all ? '?all=true' : ''}`;

let data;
try {
  data = await new Promise((resolve, reject) => {
    const req = http.request({ socketPath: '/var/run/docker.sock', path, method: 'GET' }, res => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { reject(e); } });
    });
    req.on('error', reject);
    req.setTimeout(10000, () => { req.destroy(); reject(new Error('timeout')); });
    req.end();
  });
} catch(e) {
  msg.payload = JSON.stringify({ error: e.message });
  return msg;
}

msg.payload = JSON.stringify(data.map(c => ({
  id: c.Id.slice(0, 12),
  name: (c.Names[0] || '').replace(/^\//, ''),
  image: c.Image,
  state: c.State,
  status: c.Status,
  ports: (c.Ports || []).filter(p => p.PublicPort).map(p => `${p.PublicPort}:${p.PrivatePort}`)
})));
return msg;

const { name } = msg.payload;

let statusCode;
try {
  statusCode = await new Promise((resolve, reject) => {
    const req = http.request({
      socketPath: '/var/run/docker.sock',
      path: `/containers/${encodeURIComponent(name)}/start`,
      method: 'POST'
    }, res => { res.resume(); resolve(res.statusCode); });
    req.on('error', reject);
    req.setTimeout(30000, () => { req.destroy(); reject(new Error('timeout')); });
    req.end();
  });
} catch(e) {
  msg.payload = JSON.stringify({ error: e.message }); return msg;
}

msg.payload = JSON.stringify(
  statusCode === 204 ? { success: true, name } :
  statusCode === 304 ? { success: true, name, note: 'already running' } :
  statusCode === 404 ? { error: `Container not found: ${name}` } :
  { error: `Docker API returned HTTP ${statusCode}` }
);
return msg;

const { name, timeout } = msg.payload;
const qs = timeout != null ? `?t=${timeout}` : '';

let statusCode;
try {
  statusCode = await new Promise((resolve, reject) => {
    const req = http.request({
      socketPath: '/var/run/docker.sock',
      path: `/containers/${encodeURIComponent(name)}/stop${qs}`,
      method: 'POST'
    }, res => { res.resume(); resolve(res.statusCode); });
    req.on('error', reject);
    req.setTimeout(60000, () => { req.destroy(); reject(new Error('timeout')); });
    req.end();
  });
} catch(e) {
  msg.payload = JSON.stringify({ error: e.message }); return msg;
}

msg.payload = JSON.stringify(
  statusCode === 204 ? { success: true, name } :
  statusCode === 304 ? { success: true, name, note: 'already stopped' } :
  statusCode === 404 ? { error: `Container not found: ${name}` } :
  { error: `Docker API returned HTTP ${statusCode}` }
);
return msg;

const { name, timeout } = msg.payload;
const qs = timeout != null ? `?t=${timeout}` : '';

let statusCode;
try {
  statusCode = await new Promise((resolve, reject) => {
    const req = http.request({
      socketPath: '/var/run/docker.sock',
      path: `/containers/${encodeURIComponent(name)}/restart${qs}`,
      method: 'POST'
    }, res => { res.resume(); resolve(res.statusCode); });
    req.on('error', reject);
    req.setTimeout(60000, () => { req.destroy(); reject(new Error('timeout')); });
    req.end();
  });
} catch(e) {
  msg.payload = JSON.stringify({ error: e.message }); return msg;
}

msg.payload = JSON.stringify(
  statusCode === 204 ? { success: true, name } :
  statusCode === 404 ? { error: `Container not found: ${name}` } :
  { error: `Docker API returned HTTP ${statusCode}` }
);
return msg;

const { name, lines } = msg.payload;
const tail = lines || 50;

let raw;
try {
  raw = await new Promise((resolve, reject) => {
    const req = http.request({
      socketPath: '/var/run/docker.sock',
      path: `/containers/${encodeURIComponent(name)}/logs?stdout=true&stderr=true&tail=${tail}&timestamps=true`,
      method: 'GET'
    }, res => {
      if (res.statusCode === 404) { resolve(null); return; }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(Buffer.concat(chunks)));
    });
    req.on('error', reject);
    req.setTimeout(10000, () => { req.destroy(); reject(new Error('timeout')); });
    req.end();
  });
} catch(e) {
  msg.payload = JSON.stringify({ error: e.message }); return msg;
}

if (!raw) { msg.payload = JSON.stringify({ error: `Container not found: ${name}` }); return msg; }

let logs = '';
if (raw.length > 8 && raw[0] <= 2 && raw[1] === 0 && raw[2] === 0 && raw[3] === 0) {
  let offset = 0;
  while (offset + 8 <= raw.length) {
    const size = raw.readUInt32BE(offset + 4);
    if (!size || offset + 8 + size > raw.length) break;
    logs += raw.slice(offset + 8, offset + 8 + size).toString('utf8');
    offset += 8 + size;
  }
} else {
  logs = raw.toString('utf8');
}

msg.payload = JSON.stringify({ name, logs: logs.trim() });
return msg;
